    pushReviewUndoSnapshot: () => {
      const state = get();
      const snapshot: DecisionSnapshot = {
        hunkDecisions: { ...state.hunkDecisions },
        fileDecisions: { ...state.fileDecisions },
      };
      const stack = [...state.reviewUndoStack, snapshot];
      if (stack.length > MAX_REVIEW_UNDO_DEPTH) {
        stack.shift();
